export const fencedCodeBlockMatcher=/```[\s\S]*?```/g;export const inlineCodeMatcher=/`[^`]+`/g;const scriptExtractor=/<script\b[^>]*>([\s\S]*?)<\/script>/gm;export const importMatcher=/import[^'"]+['"][^'"]+['"]/g;export const importsWithinScripts=t=>{const r=[];let o;for(;o=scriptExtractor.exec(t);)for(const t of o[1].matchAll(importMatcher))r.push(t);return r.join(";\n")};const scriptBodyExtractor=/<script\b[^>]*>(?<body>[\s\S]*?)<\/script>/gm;export const scriptBodies=t=>{const r=[];let o;for(;o=scriptBodyExtractor.exec(t);)o.groups?.body&&r.push(o.groups.body);return r.join(";\n")};export const frontmatterMatcher=/^---\r?\n([\s\S]*?)\r?\n---/;export const importsWithinFrontmatter=(t,r=[])=>{const o=t.match(frontmatterMatcher)?.[1];if(!o)return"";return r.flatMap(t=>{const r=new RegExp(`${t}:\\s*["']([^"']+)["']`,"i"),c=o.match(r);return c?.[1]?[`import ${t} from "${c[1]}";`]:[]}).join("\n")};